mapper.select:
SELECT id, user_id, product_id, product_name, product_image_url, points_cost, status, points_transaction_id, created_at, updated_at, created_by, updated_by, deleted, version FROM orders WHERE deleted = 0
AND product_name LIKE CONCAT('%', #{keyword}, '%')
AND created_at >= #{startDate}
AND created_at <= #{endDate}
ORDER BY created_at DESC
